use std::collections::BinaryHeap;
use std::cmp::Reverse;

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n as usize;
    let mut original_adj = vec![vec![]; n];
    let mut reversed_adj = vec![vec![]; n];

    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2];
        original_adj[u].push((v, w));
        reversed_adj[v].push((u, w));
    }

    let mut heap = BinaryHeap::new();
    heap.push(Reverse((0, 0, false)));

    let mut visited = vec![vec![i64::MAX; 2]; n];
    visited[0][0] = 0;

    while let Some(Reverse((current_cost, u, used_switch))) = heap.pop() {
        if u == n - 1 {
            return current_cost;
        }

        if current_cost > visited[u][used_switch as usize] {
            continue;
        }

        // Explore original edges
        for &(v, w) in &original_adj[u] {
            let new_cost = current_cost + w;
            if new_cost < visited[v][used_switch as usize] {
                visited[v][used_switch as usize] = new_cost;
                heap.push(Reverse((new_cost, v, used_switch)));
            }
        }

        // Explore reversed edges if switch hasn't been used yet
        if !used_switch {
            for &(v, w) in &reversed_adj[u] {
                let new_cost = current_cost + 2 * w;
                if new_cost < visited[v][1] {
                    visited[v][1] = new_cost;
                    heap.push(Reverse((new_cost, v, true)));
                }
            }
        }
    }

    let res = visited[n - 1][0].min(visited[n - 1][1]);
    if res != i64::MAX {
        res
    } else {
        -1
    }
}
